// interact 只绑定行为,不会创建 UI;先渲染一个可拖拽/缩放目标
const stage = document.getElementById('stage'); stage.style.cssText = 'height:360px;position:relative;overflow:hidden;border:1px solid #cbd5e1;border-radius:12px;background:#f8fafc';
const target = document.createElement('div'); target.className = 'draggable'; target.textContent = 'Drag or resize me'; target.style.cssText = 'touch-action:none;user-select:none;box-sizing:border-box;width:180px;height:96px;padding:34px 12px;text-align:center;color:white;background:#4f46e5;border-radius:10px;box-shadow:0 10px 24px #312e8150'; stage.appendChild(target);
const { default: interact } = await import('https://cdn.jsdelivr.net/npm/interactjs@1.10.27/+esm');
interact(target)
  .draggable({ ...(data.draggable ?? {}), listeners: { move(e){ const t=e.target, x=(parseFloat(t.dataset.x)||0)+e.dx, y=(parseFloat(t.dataset.y)||0)+e.dy; t.style.transform=`translate(${x}px,${y}px)`; t.dataset.x=x; t.dataset.y=y; } } })
  .resizable({ ...(data.resizable ?? {}), edges:data.resizable?.edges ?? {left:true,right:true,top:true,bottom:true}, listeners: { move(e){ Object.assign(e.target.style, { width:e.rect.width+'px', height:e.rect.height+'px' }); } } });

